<template>
  <div class="qrcode-container">
    <!-- <canvas ref="qrcodeCanvas"></canvas> -->
    <!-- 或者使用 img 标签 -->
    <img :src="qrCodeUrl" v-if="qrCodeUrl" alt="QR Code" :width="iwidth">
  </div>
</template>

<script>
import QRCode from 'qrcode'

export default {
  name: 'QRCode',
  props: {
    text: {
      type: String,
      required: true,
      default: '',
    },
    width: {
      type: Number,
      default: 200,
    },
    iwidth: {
      type: Number,
      default: 200,
    },
    colorDark: {
      type: String,
      default: '#000000',
    },
    colorLight: {
      type: String,
      default: '#ffffff',
    },
    margin: {
      type: Number,
      default: 1,
    },
  },
  data() {
    return {
      qrCodeUrl: '',
    }
  },
  watch: {
    text: {
      immediate: true,
      handler(newText) {
        if (newText) {
          this.generateQRCode()
        }
      },
    },
  },
  methods: {
    async generateQRCode() {
      try {
        const options = {
          width: this.width,
          margin: this.margin,
          color: {
            dark: this.colorDark,
            light: this.colorLight,
          },
        }
        this.qrCodeUrl = await QRCode.toDataURL(this.text, options)
      } catch (error) {
        console.error('生成二维码失败:', error)
      }
    },
    async downloadQRCode(filename = 'qrcode.png') {
      try {
        const dataUrl = await QRCode.toDataURL(this.text)
        const link = document.createElement('a')
        link.href = dataUrl
        link.download = filename
        link.click()
      } catch (error) {
        console.error('下载二维码失败:', error)
      }
    },
  },
}
</script>

<style scoped>
.qrcode-container {
  display: inline-block;
  padding: 10px;
  background: white;
  border-radius: 8px;
  /* box-shadow: 0 2px 8px rgba(0,0,0,0.1); */
}
</style>
